149	export function getMarket(
150	  marketId: string,
151	): Promise<MarketDetailResponse> {
152	  return request<MarketDetailResponse>(`/v1/markets/${encodeURIComponent(marketId)}`);
153	}
154	
155	function joinUrlPath(basePath: string, path: string): string {
156	  const normalizedBase = basePath === "/" ? "" : basePath.replace(/\/$/, "");
157	  const normalizedPath = path.startsWith("/") ? path : `/${path}`;
158	  return `${normalizedBase}${normalizedPath}`;
159	}
160	
161	export function getMarketPricesWebSocketUrl(marketId: string): string {
162	  const baseUrl = API_BASE
163	    ? new URL(API_BASE, window.location.origin)
164	    : new URL(window.location.origin);
165	  const socketUrl = new URL(baseUrl.toString());
166	  socketUrl.protocol = socketUrl.protocol === "https:" ? "wss:" : "ws:";
167	  socketUrl.pathname = joinUrlPath(
168	    socketUrl.pathname,
169	    `/ws/markets/${encodeURIComponent(marketId)}/prices`,
170	  );
171	  socketUrl.search = "";
172	  socketUrl.hash = "";
173	  return socketUrl.toString();
174	}
