38	interface PositionLimitExceededDetails {
39	  requestedSize: number | null;
40	  currentNetSize: number | null;
41	  resultingNetSize: number | null;
42	  maxPositionSize: number | null;
43	}
44	
45	function readNumericDetail(value: unknown): number | null {
46	  return typeof value === "number" && Number.isFinite(value) ? value : null;
47	}
48	
49	function readPositionLimitDetails(error: BayesApiError): PositionLimitExceededDetails {
50	  return {
51	    requestedSize: readNumericDetail(error.details.requestedSize),
52	    currentNetSize: readNumericDetail(error.details.currentNetSize),
53	    resultingNetSize: readNumericDetail(error.details.resultingNetSize),
54	    maxPositionSize: readNumericDetail(error.details.maxPositionSize),
55	  };
56	}
57	
58	function formatPositionSize(value: number): string {
59	  return value.toFixed(2);
60	}
61	
62	function formatTradeError(error: unknown): string {
63	  if (!(error instanceof BayesApiError) || error.code !== "position_limit_exceeded") {
64	    return error instanceof Error ? error.message : "Trade failed";
65	  }
66	
67	  const { requestedSize, currentNetSize, resultingNetSize, maxPositionSize } = readPositionLimitDetails(error);
68	  if (
69	    requestedSize == null
70	    || currentNetSize == null
71	    || resultingNetSize == null
72	    || maxPositionSize == null
73	  ) {
74	    return "Position limit exceeded. Trade would exceed the max position size for this outcome.";
75	  }
76	
77	  return `Position limit exceeded. Requested size ${formatPositionSize(requestedSize)} would move net size from ${formatPositionSize(currentNetSize)} to ${formatPositionSize(resultingNetSize)}; max position size is ${formatPositionSize(maxPositionSize)}.`;
78	}
