- `GET /v1/markets/{marketId}/accounts/{accountId}/pnl` - Get market P&L
- `GET /v1/accounts/{accountId}/risk` - Get account risk
- `GET /v1/accounts/{accountId}/exposure` - Get account exposure
- `GET /v1/accounts/{accountId}/pnl` - Get account P&L
- `GET /health` - Health check
- `GET /` - Service index

**WebSocket URLs:**
- `ws://[base]/ws/markets/{marketId}/prices` - Market price updates
- `ws://[base]/ws/markets/{marketId}/events` - Market events
- `ws://[base]/ws/accounts/{accountId}/risk` - Account risk updates

---

### 2. API RESPONSE TYPES

**File:** `/tmp/temporal-worktrees/task-e2e-tests-001/frontend/src/lib/api/types.ts`

**Session Object:**
```typescript
interface Session {
  accountId: string;
  agentId: string;
}
```

**Market Summary (from list):**
```typescript
interface MarketSummary {
  id: string;
  title: string;
  status: "active" | "resolved" | "closed" | "draft";
  liquidity: number;
  volume: number;
  expires_at: string;
}
```

**Market Detail (full):**
```typescript
interface Market {
  id: string;
  title: string;
  description: string;
  variableId: string;
  status: "active" | "resolved" | "closed" | "draft";
  resolution?: string;
  resolutionProbabilities?: Record<string, number>;
  outcomes: MarketOutcome[];
  marginals: Record<string, number>;  // probability per outcome
  liquidity: number;
  volume: number;
  created_at: string;
  expires_at: string;
}

interface MarketOutcome {
  id: string;
  name: string;
}
```

**Market List Response:**
```typescript
interface MarketListResponse {
  markets: MarketSummary[];
  count: number;
  meta: {
    filters: {
      status: MarketStatus | null;
      include_resolved: boolean;
      sort?: MarketSortField;
      q?: string;
    };
    apiVersion: string;
    timestamp: string;
  };
}
```

**Market Detail Response:**
```typescript
interface MarketDetailResponse {
  market: Market;
  meta: Meta;
}
```

**EventTradeOrder & Response:**
```typescript
interface EventTradeOrder {
  id: string;
  type: "EventTrade";
  marketId: string;
  accountId: string;
  commandId: string;
  submittedAt: string;
  status: "filled";
  payload: EventTradeOrderPayload;
  targetMarketId: string;
  targetOutcomeId: string;
  side: "buy" | "sell";
  size: number;
  price: number;
  notional: number;
  createdAt: string;
  filledAt: string;
  idempotencyKey?: string;
}

interface EventTradeResponse {
  order: EventTradeOrder;
  result: AcceptedTerminalResult;
  meta: CommandResponseMeta;
}
```

**Market Comment:**
```typescript
interface MarketComment {
  commentId: string;
  marketId: string;
  seq: number;
  accountId: string;
  body: string;
  createdAt: string;
}

interface MarketCommentsResponse {
  marketId: string;
  comments: MarketComment[];
  pagination: {
    fromSeq: number;
    limit: number;
    returned: number;
    nextFromSeq: number | null;
  };
  meta: Meta;
}
```

**Account Exposure:**
```typescript
interface AccountExposurePosition {
  marketId: string;
  outcomeId: string;
  netSize: number;
  absSize: number;
  lastTradePrice: number;
  updatedAt: string;
  lastOrderId: string | null;
  lastCommandId: string | null;
}

interface AccountExposureResponse {
  account: {
    id: string;
    exposure: {
      maxPositionSize: number;
      updatedAt: string;
      positions: AccountExposurePosition[];
    };
  };
  meta: Meta;
}
```

**Account Risk:**
```typescript
interface AccountRiskResponse {
  account: {
    id: string;
    risk: {
      minAssets: {
        overall: number;
        markets: MarketRisk[];
      };
      capacityIndicators: {
        limit: number;
        available: number;
        consumed: number;
        utilization: number;
        status: "healthy" | "warning" | "critical";
      };
      updatedAt: string;
    };
  };
  meta: Meta;
}
```

**P&L Response:**
```typescript
interface OutcomePnl {
  outcomeId: string;
  netSize: number;
  costBasis: number;
  currentValue: number;
  unrealizedPnl: number;
  realizedPnl: number;
  totalPnl: number;
}

interface MarketPnlResponse {
  pnl: {
    marketId: string;
    outcomes: Record<string, OutcomePnl>;
    summary: {
      totalCostBasis: number;
      totalCurrentValue: number;
      totalUnrealizedPnl: number;
      totalRealizedPnl: number;
      totalPnl: number;
    };
  };
  meta: { timestamp: string };
}

interface AccountPnlResponse {
  pnl: {
    accountId: string;
    markets: AccountPnlMarket[];  // Array of markets with their P&L
    summary: MarketPnlSummary;
  };
  meta: { timestamp: string };
}
```

