2	import { useEventTrade } from "@/lib/query/hooks";
3	import { useSession } from "@/features/session/context";
4	import { BayesApiError } from "@/lib/api/client";
5	import type { EventTradeOrder, Market } from "@/lib/api/types";
6	
7	function TradeReceipt({ order, outcomeLabel }: { order: EventTradeOrder; outcomeLabel: string }) {
8	  return (
9	    <div style={{ display: "grid", gridTemplateColumns: "repeat(5, 1fr)", gap: "var(--space-sm)", marginTop: "var(--space-xs)", fontSize: "0.75rem" }}>
10	      <div>
11	        <div style={{ color: "var(--color-text-muted)" }}>Side</div>
12	        <div style={{ fontFamily: "var(--font-mono)" }}>{order.side}</div>
13	      </div>
14	      <div>
15	        <div style={{ color: "var(--color-text-muted)" }}>Outcome</div>
16	        <div style={{ fontFamily: "var(--font-mono)" }}>{outcomeLabel}</div>
17	      </div>
18	      <div>
19	        <div style={{ color: "var(--color-text-muted)" }}>Size</div>
20	        <div style={{ fontFamily: "var(--font-mono)" }}>{order.size.toFixed(2)}</div>
21	      </div>
22	      <div>
23	        <div style={{ color: "var(--color-text-muted)" }}>Price</div>
24	        <div style={{ fontFamily: "var(--font-mono)" }}>{(order.price * 100).toFixed(1)}%</div>
25	      </div>
26	      <div>
27	        <div style={{ color: "var(--color-text-muted)" }}>Notional</div>
28	        <div style={{ fontFamily: "var(--font-mono)" }}>{order.notional.toFixed(2)}</div>
29	      </div>
30	    </div>
31	  );
32	}
33	
34	interface Props {
35	  market: Market;
36	}
37	
38	interface PositionLimitExceededDetails {
39	  requestedSize: number | null;
40	  currentNetSize: number | null;
41	  resultingNetSize: number | null;
42	  maxPositionSize: number | null;
43	}
44	
45	function readNumericDetail(value: unknown): number | null {
46	  return typeof value === "number" && Number.isFinite(value) ? value : null;
47	}
48	
49	function readPositionLimitDetails(error: BayesApiError): PositionLimitExceededDetails {
50	  return {
51	    requestedSize: readNumericDetail(error.details.requestedSize),
52	    currentNetSize: readNumericDetail(error.details.currentNetSize),
53	    resultingNetSize: readNumericDetail(error.details.resultingNetSize),
54	    maxPositionSize: readNumericDetail(error.details.maxPositionSize),
55	  };
56	}
57	
58	function formatPositionSize(value: number): string {
59	  return value.toFixed(2);
60	}
61	
62	function formatTradeError(error: unknown): string {
63	  if (!(error instanceof BayesApiError) || error.code !== "position_limit_exceeded") {
64	    return error instanceof Error ? error.message : "Trade failed";
65	  }
66	
67	  const { requestedSize, currentNetSize, resultingNetSize, maxPositionSize } = readPositionLimitDetails(error);
68	  if (
69	    requestedSize == null
70	    || currentNetSize == null
71	    || resultingNetSize == null
72	    || maxPositionSize == null
73	  ) {
74	    return "Position limit exceeded. Trade would exceed the max position size for this outcome.";
75	  }
76	
77	  return `Position limit exceeded. Requested size ${formatPositionSize(requestedSize)} would move net size from ${formatPositionSize(currentNetSize)} to ${formatPositionSize(resultingNetSize)}; max position size is ${formatPositionSize(maxPositionSize)}.`;
78	}
79	
80	export function EventTradePanel({ market }: Props) {
81	  const { session, isConfigured } = useSession();
82	  const mutation = useEventTrade(market.id);
83	  const [selectedOutcome, setSelectedOutcome] = useState<string>("");
84	  const [size, setSize] = useState<string>("1");
85	  const [side, setSide] = useState<"buy" | "sell">("buy");
86	
87	  if (market.status !== "active") return null;
88	  if (!isConfigured) return null;
89	
90	  const currentPrice = selectedOutcome ? (market.marginals[selectedOutcome] ?? 0) : 0;
91	  const parsedSize = Number(size);
92	  const isValidSize = Number.isFinite(parsedSize) && parsedSize > 0;
93	  const canSubmit = selectedOutcome.length > 0 && isValidSize && !mutation.isPending;
94	  const inlineErrorMessage = mutation.isError ? formatTradeError(mutation.error) : null;
95	
96	  const handleTrade = () => {
97	    if (!selectedOutcome || !isValidSize) return;
98	
99	    mutation.mutate({
100	      payload: {
101	        accountId: session.accountId,
102	        formula: [[{
103	          variableId: market.id,
104	          outcomeId: selectedOutcome,
105	          negated: false,
106	        }]],
107	        size: parsedSize,
108	        side,
109	        idempotencyKey: crypto.randomUUID(),
110	      },
111	      session,
112	    });
113	  };
114	
115	  return (
116	    <div style={panelStyle}>
117	      <div style={{ fontSize: "0.85rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
118	        Quick Trade
119	      </div>
120	
121	      <div style={{ display: "flex", gap: "var(--space-sm)", alignItems: "center", flexWrap: "wrap" }}>
122	        {/* Side toggle */}
123	        <div style={{ display: "flex", borderRadius: "var(--radius-sm)", overflow: "hidden", border: "1px solid var(--color-border)" }}>
124	          <button
125	            onClick={() => setSide("buy")}
126	            style={{
127	              ...sideBtnStyle,
128	              background: side === "buy" ? "var(--color-success, #22c55e)" : "transparent",
129	              color: side === "buy" ? "#fff" : "var(--color-text-muted)",
130	            }}
131	          >
132	            Buy
133	          </button>
134	          <button
135	            onClick={() => setSide("sell")}
136	            style={{
137	              ...sideBtnStyle,
138	              background: side === "sell" ? "var(--color-danger, #ef4444)" : "transparent",
139	              color: side === "sell" ? "#fff" : "var(--color-text-muted)",
140	            }}
141	          >
142	            Sell
143	          </button>
144	        </div>
145	
146	        <label style={fieldGroupStyle}>
147	          <span style={fieldLabelStyle}>Outcome</span>
148	          <select
149	            value={selectedOutcome}
150	            onChange={(e) => setSelectedOutcome(e.target.value)}
151	            style={selectStyle}
152	            aria-label="Trade outcome"
153	          >
154	            <option value="">Select outcome...</option>
155	            {market.outcomes.map((o) => (
156	              <option key={o.id} value={o.id}>
157	                {o.name} @ {((market.marginals[o.id] ?? 0) * 100).toFixed(1)}%
158	              </option>
159	            ))}
160	          </select>
161	        </label>
162	
163	        {selectedOutcome && (
164	          <span style={{ fontSize: "0.8rem", color: "var(--color-text-muted)" }}>
165	            Price: {(currentPrice * 100).toFixed(1)}%
166	          </span>
167	        )}
168	
169	        <label style={fieldGroupStyle}>
170	          <span style={fieldLabelStyle}>Position Size</span>
171	          <input
172	            type="number"
173	            inputMode="decimal"
174	            min="0.000001"
175	            step="0.1"
176	            value={size}
177	            onChange={(e) => setSize(e.target.value)}
178	            style={sizeInputStyle}
179	            aria-label="Position size"
180	          />
181	        </label>
182	
183	        <button
184	          onClick={handleTrade}
185	          disabled={!canSubmit}
186	          style={{
187	            ...tradeBtnStyle,
188	            background: side === "buy" ? "var(--color-success, #22c55e)" : "var(--color-danger, #ef4444)",
189	            opacity: canSubmit ? 1 : 0.5,
190	            cursor: canSubmit ? "pointer" : "not-allowed",
191	          }}
192	        >
193	          {mutation.isPending
194	            ? "Submitting..."
195	            : `${side === "buy" ? "Buy" : "Sell"} ${selectedOutcome || "..."} (${size || "0"})`}
196	        </button>
197	      </div>
198	
199	      {mutation.isSuccess && (
200	        <div style={successStyle}>
201	          <div>Trade accepted - Order {mutation.data.order.id}</div>
202	          <TradeReceipt
203	            order={mutation.data.order}
204	            outcomeLabel={
205	              market.outcomes.find((outcome) => outcome.id === mutation.data.order.targetOutcomeId)?.name
206	              ?? mutation.data.order.targetOutcomeId
207	            }
208	          />
209	        </div>
210	      )}
211	
212	      {inlineErrorMessage && (
213	        <div style={errorStyle}>
214	          {inlineErrorMessage}
215	        </div>
216	      )}
217	    </div>
218	  );
219	}
220	
